"""Examine actual cues generated by different prompt versions.

Shows side-by-side cues for the same questions across versions.
"""

import json
from pathlib import Path

RESULTS_DIR = Path(__file__).resolve().parent / "results"


def examine_cues(versions_labels: list[tuple[str, str]], n_examples: int = 8) -> None:
    """Show cues for the same questions across versions."""
    # Load all result sets
    all_results = {}
    for version_name, label in versions_labels:
        path = RESULTS_DIR / f"normalized_{label}.json"
        if path.exists():
            with open(path) as f:
                all_results[version_name] = json.load(f)

    if not all_results:
        print("No results found")
        return

    # Get question keys from first version
    first_version = list(all_results.keys())[0]
    first_results = all_results[first_version]

    # Find questions where at least one version shows interesting delta
    interesting = []
    for i, r in enumerate(first_results):
        b20 = r["baseline_recalls"]["r@20"]
        best_a20 = b20  # baseline
        worst_a20 = b20
        for vn, vr in all_results.items():
            if i < len(vr):
                a20 = vr[i]["assoc_recalls"]["r@20"]
                best_a20 = max(best_a20, a20)
                worst_a20 = min(worst_a20, a20)
        spread = best_a20 - worst_a20
        if spread > 0.001:
            interesting.append((spread, i, r))

    interesting.sort(key=lambda x: x[0], reverse=True)

    print(f"Found {len(interesting)} questions with varying performance across versions")
    print()

    for spread, idx, base_r in interesting[:n_examples]:
        q = base_r["question"][:100]
        cat = base_r["category"]
        b20 = base_r["baseline_recalls"]["r@20"]
        src = base_r["source_chat_ids"]

        print(f"{'='*100}")
        print(f"Q: {q}")
        print(f"Cat: {cat}  Source: {src}  Baseline r@20: {b20:.3f}")
        print()

        for vn, vr in all_results.items():
            if idx >= len(vr):
                continue
            r = vr[idx]
            a20 = r["assoc_recalls"]["r@20"]
            delta = a20 - b20

            # Get hop 1 cues
            hop1_cues = []
            hop1_hits = []
            for h in r.get("hop_details", []):
                if h["hop"] == 1:
                    hop1_cues = h["cues"]
                    hop1_hits = h.get("new_source_hits", [])

            print(f"  [{vn:>5s}] r@20={a20:.3f} (delta={delta:+.3f}) hop1_hits={hop1_hits}")
            for c in hop1_cues:
                print(f"    CUE: {c[:120]}")
            print()


if __name__ == "__main__":
    configs = [
        ("v8", "v8_nr1_h1_beam_ext_30q"),
        ("v11", "v11_nr1_h1_beam_ext_30q"),
        ("v13", "v13_nr1_h1_beam_ext_30q"),
        ("v15", "v15_nr1_h1_beam_ext_30q"),
        ("v16", "v16_nr1_h1_beam_ext_30q"),
    ]

    print("BEAM EXAMPLES:")
    print("=" * 100)
    examine_cues(configs)

    print("\n\n\nLOCOMO EXAMPLES:")
    print("=" * 100)
    locomo_configs = [
        ("v8", "v8_nr1_h1_locomo_ext_30q"),
        ("v11", "v11_nr1_h1_locomo_ext_30q"),
        ("v13", "v13_nr1_h1_locomo_ext_30q"),
        ("v14", "v14_nr1_h1_locomo_ext_30q"),
        ("v15", "v15_nr1_h1_locomo_ext_30q"),
        ("v16", "v16_nr1_h1_locomo_ext_30q"),
    ]
    examine_cues(locomo_configs)
